const raw = $input.first().json;
const n = (raw && typeof raw === 'object' && raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body)) ? raw.body : raw;
const { pipeline_id, step, status, gate_required, artifact_paths = [], metadata = {}, event, message, agent_caller } = n;
const channel = metadata.slack_channel;
const thread_ts = metadata.slack_thread_ts;

if (!channel) {
  return [{ json: { channel: null } }];
}

const firstArtifact = artifact_paths[0] || null;
const stepLabel = (step || '').replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
const callerLabel = agent_caller || ({ planner: 'Planner', 'sprint-controller': 'Sprint-Controller', implementer: 'Implementer', verifier: 'Verifier' }[step] || stepLabel);

let text, blocks;

if (event === 'progress' && message) {
  // Lightweight progress update — post as a thread context message, no buttons
  const expectedPrefix = `${callerLabel}: `;
  text = message.startsWith(expectedPrefix) ? message : `${callerLabel}: ${message}`;
  blocks = [
    {
      type: 'context',
      elements: [
        { type: 'mrkdwn', text: text }
      ]
    }
  ];
} else if (status === 'awaiting_approval') {
  text = `\u{1F916} ${callerLabel} completed \u2014 ready for review`;
  blocks = [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `\u{1F916} *${callerLabel} completed* \u2014 Pipeline \`${pipeline_id}\` is ready for review.${ firstArtifact ? `\n*Artifact:* \`${firstArtifact}\`` : '' }`
      }
    },
    {
      type: 'actions',
      block_id: `gate_${pipeline_id}`,
      elements: [
        {
          type: 'button',
          text: { type: 'plain_text', text: '\u2705 Approve \u2192 Continue' },
          style: 'primary',
          action_id: 'approve_pipeline',
          value: pipeline_id
        },
        {
          type: 'button',
          text: { type: 'plain_text', text: '\u270B Take Over' },
          action_id: 'takeover_pipeline',
          value: pipeline_id
        }
      ]
    }
  ];
} else if (status === 'failed') {
  text = `\u26A0\uFE0F ${callerLabel} failed \u2014 ${pipeline_id}`;
  blocks = [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `\u26A0\uFE0F *${callerLabel} failed* \u2014 Pipeline \`${pipeline_id}\` needs attention.${ firstArtifact ? `\n*Findings:* \`${firstArtifact}\`` : '' }`
      }
    },
    {
      type: 'actions',
      block_id: `fail_${pipeline_id}`,
      elements: [
        {
          type: 'button',
          text: { type: 'plain_text', text: '\u270B Take Over Fix' },
          style: 'primary',
          action_id: 'takeover_pipeline',
          value: pipeline_id
        },
        {
          type: 'button',
          text: { type: 'plain_text', text: '\u23ED Skip Step' },
          style: 'danger',
          action_id: 'skip_pipeline',
          value: `${pipeline_id}::Auto-skip after failure`
        }
      ]
    }
  ];
} else if (status === 'complete') {
  text = `\u2705 Pipeline complete \u2014 ${pipeline_id}`;
  blocks = [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `\u2705 *Pipeline complete* \u2014 \`${pipeline_id}\`${ artifact_paths.length ? `\n*Artifacts:* ${ artifact_paths.map(p => `\`${p}\``).join(', ') }` : '' }`
      }
    }
  ];
} else if (status === 'paused_takeover') {
  text = `\u270B Takeover active \u2014 ${callerLabel}`;
  blocks = [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `\u270B *Takeover active* \u2014 A human owns the *${callerLabel}* step on pipeline \`${pipeline_id}\`.\nUse \`/handoff ${pipeline_id}\` when complete.`
      }
    }
  ];
} else {
  // running — progress context message
  text = `\u2699\uFE0F ${callerLabel} is running \u2014 ${pipeline_id}`;
  blocks = [
    {
      type: 'context',
      elements: [
        { type: 'mrkdwn', text: `\u2699\uFE0F *${callerLabel}* is now running \u2014 Pipeline \`${pipeline_id}\`` }
      ]
    }
  ];
}

const payload = { channel, text, blocks };
if (thread_ts) payload.thread_ts = thread_ts;

return [{ json: { channel, slack_payload: JSON.stringify(payload) } }];
